custom_css:
/* 本样式仅免费发布于Discord旅程社区。请勿二传或商用！二改请标注谢谢。感谢Junezz老师的简约卡片的正则参考。 */

/* 字体 */
@font-face {
    /* 给它起个新名字，就叫 Freedom 吧 */
    font-family: "Freedom"; 
    /* 路径对应你改名后的文件 */
    src: url("/fonts/mlk.ttf") format("truetype");
    font-weight: normal;
    font-style: normal;
}

/* 2. 应用字体 */
body {
    /* 使用新定义的 Freedom 字体，后面加上 sans-serif 兜底 */
    font-family: "Freedom", sans-serif !important;
    font-weight: normal;
}

:root {
  /* 字体名称 */
  --mainFontFamily: "BabelStone Han";
  --monoFontFamily: "BabelStone Han";
  --模糊强度: 0px;
  --气泡左右间距: 10px;
  --正文左右间距: 15px;
  --自定义文案: "❘ 我不愿醒着，月亮洒下一地纸沫。";
  --思维链标题: "想破了脑袋。";
  --图标大小: 15px;
  --crimson70a: transparent;
}

/* 输入栏间距：上，左右，下三个数值 */
#send_form, body.no-blur #send_form {
  padding: 6px 10px 10px;
}

/* 自定义部分结束 */

.mes {
  background-color: transparent;
  border-radius: 0 !important;
  border: none;
  border-bottom: 1px solid color-mix(in srgb, var(--SmartThemeBodyColor), transparent 60%) !important;
}

.last_mes {
  border: none !important;
}

body.bubblechat .mes {
  padding: 10px var(--正文左右间距);
}

/* chat + mes */
#chat {
  border: none;
  padding: 20px var(--气泡左右间距);
}

#chat .mes + .mes {
  margin-top: 50px;
}

.mes_block .ch_name {
  margin-bottom: 10px; /* 头像区域与正文 */
}

.last_mes .mesAvatarWrapper {
  padding-bottom: 0px;
}

/* 头像区域 */
.mes {
  position: relative;
  flex-direction: column;
}

body.no-blur #chat {
  backdrop-filter: blur(var(--模糊强度)) !important;
}

.mes .avatar {
  position: absolute;
  top: 20px;
  left: 50%;
  transform: translateX(-50%);
}

.mes .ch_name .alignItemsBaseline {
  position: absolute;
  top: 80px; /* 20+头像高度50 */
  gap: 7px; /* 间距7 */
  left: 50%;
  transform: translateX(-50%);
  flex-direction: column;
  align-items: center !important;
  white-space: nowrap;
}

/* 隐藏 */
.mes[is_system="true"] .ch_name .alignItemsBaseline {
  flex-direction: row;
  flex-wrap: wrap;
  justify-content: center;
}

.mes[is_system="true"] .timestamp {
  flex-basis: 100%;
  text-align: center;
}

.mes[is_system="true"] .mes_ghost {
  align-self: center;
}

.mesAvatarWrapper {
  position: absolute;
  top: 0;
  left: var(--正文左右间距);
  right: var(--正文左右间距);
  height: 190px; /* 高度190 */
  display: flex;
  align-items: end;
}

.mes .mes_block {
  margin-top: 240px; /* 高度240 */
}

.mes .mesIDDisplay { order: 1; }
.mes .tokenCounterDisplay { order: 2; }
.mes .mes_timer { order: 3; }

.mes .tokenCounterDisplay {
  margin-left: auto;
}

.mes .mes_timer {
  margin-left: 5px; /* 间距5 */
}

/* 字体样式 */
.mes .name_text, .mes .timestamp, .mes .mes_timer, .mes .tokenCounterDisplay, .mes .mesIDDisplay {
  font-weight: normal;
  opacity: 1;
}

.mes .name_text, .mes .timestamp {
  font-size: calc(var(--mainFontSize) * 0.9);
  letter-spacing: 3px;
}

.mes .mes_timer, .mes .tokenCounterDisplay {
  font-size: calc(var(--mainFontSize) * 0.9);
  margin-bottom: 5px;
}

.mes .mesIDDisplay {
  font-size: calc(var(--mainFontSize) * 1.5);
}

/* 样式 */
.mes .name_text::before {
  content: "作/";
}

.mes .timestamp::before {
  content: "-";
  margin-right: 8px;
}

.mes .timestamp::after {
  content: "-";
  margin-left: 8px;
}

.mes .tokenCounterDisplay::before {
  content: "字数";
  margin-right: 3px;
}

.mes .tokenCounterDisplay::after {
  content: "|";
  margin-left: 3px;
}

.mes .mes_timer::before {
  content: "更新于";
  margin-right: 3px;
}

.mes .mes_timer::after {
  content: "前";
  margin-left: 3px;
}

.mes .mesIDDisplay::before {
  content: "章";
  margin-right: 3px;
}

/* 自定义文案 */
.mes .mesAvatarWrapper::after {
  content: var(--自定义文案);
  position: absolute;
  bottom: -30px;
  left: 0;
  font-size: calc(var(--mainFontSize) * 1.1);
  white-space: nowrap;
}

/* 按钮图标 */
.mes_buttons .fa-pencil::before, .mes_buttons .fa-ellipsis::before {
  font-size: calc(var(--mainFontSize) * 0.9);
  font-weight: normal;
  vertical-align: top;
}

.mes_buttons .fa-pencil::before {
  content: "摘抄";
}

.mes_buttons .fa-ellipsis::before {
  content: "展开";
}

.mes_buttons .fa-code-branch::before {
  content: "分支";
  font-size: calc(var(--mainFontSize) * 0.9);
  font-weight: normal;
  vertical-align: top;
}

.mes_buttons, .extraMesButton {
  align-items: start;
  padding: 0;
}

/* 单独常驻显示“分支”，其余操作仍通过“展开”打开 */
.mes_buttons .extraMesButtons {
  display: flex !important;
  opacity: 1 !important;
}

.mes_buttons .extraMesButtons > .mes_button:not(.mes_create_branch) {
  display: none !important;
}

.mes_buttons .extraMesButtons.visible > .mes_button {
  display: inline-block !important;
}

.mes_button, .extraMesButtons>div, .favorite-toggle-icon, .mes_edit_buttons .menu_button, .mes_reasoning_actions .edit_button {
  opacity: 0.7 !important;
  filter: none !important;
  background-color: transparent;
  padding: 0 3px;
  font-size: calc(var(--mainFontSize) * 0.9);
}

.mes_edit_buttons .menu_button, .mes_reasoning_actions .edit_button {
  border-color: var(--SmartThemeBodyColor);
}

.mes_edit_buttons {
  filter: none;
  margin-top: 20px;
}

/* top bar + send form */
#send_form, body.no-blur #send_form, #top-bar, body.no-blur #top-bar {
  outline: none !important;
  border: none !important;
  box-shadow: none;
  border-radius: 0;
  backdrop-filter: blur(var(--模糊强度)) !important;
}

#top-settings-holder .drawer-icon {
  font-size: var(--图标大小) !important;
}

#rightSendForm>div, #leftSendForm>div, #rightSendForm > div > [class*="fa-"], #rightSendForm > div > i, #quickPersona {
  font-size: calc(var(--图标大小) + 3px) !important;
}

#rightSendForm>div:not(.mes_stop), #leftSendForm>div {
  opacity: 1;
}

#send_form .mes_stop {
  padding: 0px 10px;
  opacity: 1;
}

#send_textarea, #send_textarea:focus {
  clip-path: none !important;
  border: none;
  backdrop-filter: none !important;
}

#send_textarea::placeholder {
  color: transparent !important;
}

/* 菜单 */
#left-nav-panel,
#completion_prompt_manager_popup,
#rm_api_block,
#AdvancedFormatting,
#WorldInfo,
#user-settings-block,
#Backgrounds,
#rm_extensions_block,
.drawer-content.openDrawer,
#right-nav-panel,
body.no-blur .popup, body.no-blur #bulk_tag_popup, body.no-blur #dialogue_popup,
#options, #extensionsMenu, .popup .popper-modal {
  border: none;
  padding: 10px;
  border-radius: 0px;
  box-shadow: none;
  backdrop-filter: blur(var(--模糊强度)) !important;
}

#form_sheld {
  margin: 0 auto !important;
}

#sheld {
  top: var(--bottomFormBlockSize);
  height: calc(100dvh - var(--bottomFormBlockSize));
  max-height: calc(100dvh - var(--bottomFormBlockSize));
}

/* 图标样式 */
.fa, .fa-brands, .fa-classic, .fa-regular, .fa-sharp, .fa-solid:not(.fav_on, .world_set, .fa-power-off, .fa-chevron-right, .fa-chevron-left), .fab, .far, .fas {
  color: var(--SmartThemeUnderlineColor) !important;
  font-size: var(--图标大小) !important;
  filter: none;
  opacity: 1;
}

/* 图标按钮样式 */
.menu_button {
  color: var(--SmartThemeUnderlineColor);
  filter: none;
  background-color: transparent;
  border: none;
}

input:not(input[type="range"], input[type='checkbox']), .text_pole, .textarea_compact, textarea:not(.select2-search__field),
#qr--settings #qr--set-qrList .qr--set-qrListContents > .qr--set-item .qr--content .qr--set-itemMessage,
.select2-dropdown,
#extensionSideBar #extensionSideBarContainer .sideBarItem.selected,
.select_chat_block[highlight] {
  background-color: transparent !important;
  border: none !important;
  border-radius: 0px;
}

select:focus-visible, input:focus-visible, textarea:not(#send_textarea):focus-visible {
  outline: none !important;
  border-left: 1px solid var(--SmartThemeBodyColor) !important;
  padding-left: 10px;
}

/* 标题 */
strong::before, b::before, h4:not(.margin0) span::before, #persona-management-button.drawer .standoutHeader::before {
  content: "﹥";
  margin-right: 5px;
}

#extensions_settings .inline-drawer-toggle.inline-drawer-header, #extensions_settings2 .inline-drawer-toggle.inline-drawer-header, #user-settings-block h4, .standoutHeader, .inline-drawer-header {
  border: none;
  background-image: none;
}

h3.margin0 span:not(.note-link-span)::before, h3.margin0.flex1::before, h3.margin0.flex2::before, #rm_button_selected_ch h2::before {
  content: "《";
}

h3.margin0 span:not(.note-link-span)::after, h3.margin0.flex1::after, h3.margin0.flex2::after, #rm_button_selected_ch h2::after {
  content: "》";
}

/* Spacing */
.text_pole, select, .range-block-range-and-counter, .range-block, .range-block-title, .WIEntryHeaderTitleMobile, h1, h2, h3 {
  margin: 3px !important;
}

#anchor_checkbox label, #power-user-option-checkboxes label, .checkbox_label, .auto_continue_settings_block {
  margin: 5px 0px;
}

/* 勾选框 */
input[type="checkbox"] {
  background-color: transparent;
  border: none;
  outline: none;
  filter: none;
  box-shadow: none;
}

input[type="checkbox"]::before {
  box-shadow: inset 1em 1em var(--SmartThemeBodyColor);
}

/* 滑动条 */
input[type="range"], input[type="range"]:disabled {
  filter: none;
  box-shadow: none !important;
  background-color: var(--SmartThemeBodyColor) !important;
  height: 1px !important;
  border-radius: 0px !important;
}

input[type="range"]::-webkit-slider-thumb {
  border: none;
  cursor: pointer;
  background-color: var(--SmartThemeBodyColor);
  box-shadow: none;
  width: 10px;
  height: 10px;
}

/* 下拉选择栏 */
.select2-dropdown {
  box-shadow: none;
  background-color: var(--SmartThemeBlurTintColor) !important;
}

/* 修复：为下拉框添加最小样式，防止透明 */
select,
.select2-container--default .select2-selection--single,
.select2-container--default .select2-selection--multiple {
  background-color: transparent !important;
  border: 1px solid color-mix(in srgb, var(--SmartThemeBodyColor), transparent 60%) !important;
  border-radius: 0px !important;
}

/* 修复：世界书条目背景 */
.select2_multi_sameline+span.select2-container .select2-selection--multiple .select2-selection__choice {
    background-color: color-mix(in srgb, var(--SmartThemeBodyColor), transparent 85%) !important;
    border: 1px solid color-mix(in srgb, var(--SmartThemeBodyColor), transparent 70%) !important;
}


/* 正文编辑 */
.mes .reasoning_edit_textarea, .mes .edit_textarea {
  background-color: transparent !important;
  border: none !important;
  margin: 0;
  padding: 0;
  outline: none !important;
  box-shadow: none !important;
}

.mes .edit_textarea {
  padding: var(--正文左右间距) !important;
  margin: 30px 0 !important;
}

/* 正文 */
.mes_block {
  padding: 0 3px;
}

.mes_text {
  padding: 0;
  text-align: justify;
  line-height: 1.6;
}

.mes_text em, .mes_text code:not(pre code.hljs) {
  background-color: transparent;
  color: var(--SmartThemeShadowColor);
  padding: 0px;
  border: none;
  font-style: normal;
}

.mes_text em::before, .mes_text code:not(pre code.hljs)::before {
  content: "﹤";
}

.mes_text em::after, .mes_text code:not(pre code.hljs)::after {
  content: "﹥";
}

/* 思维链 */
.mes_reasoning_details {
  max-width: 90%;
  margin: 0 auto 20px;
  position: relative;
  border: 1px solid var(--SmartThemeBodyColor);
  padding: 15px;
}

/* 按钮不溢出 */
.mes_reasoning_summary {
  margin-right: 0 !important;
}

.mes_reasoning_actions {
  margin: 0;
  align-items: center;
}

/* 内容 */
.mes_reasoning {
  color: var(--SmartThemeBodyColor);
  border-top: 1px solid var(--SmartThemeBodyColor);
  border-left: none;
  padding: 15px 0 0;
  margin: 5px 0 0;
  font-size: calc(var(--mainFontSize) * 0.9);
}

/* * 这里的修改：
 * 1. 符号从 "❝" 改为 "「"
 */
.mes_reasoning_details::before, .mes_text pre code::before, .mes_text blockquote::before {
  content: "「";
  position: absolute;
  top: -10px;
  left: 10px;
  font-size: 1.5em;
  line-height: 1;
  color: var(--SmartThemeBodyColor);
}

/* * 这里的修改：
 * 1. 符号从 "❞" 改为 "」"
 */
.mes_reasoning_details::after, .mes_text pre code::after, .mes_text blockquote::after {
  content: "」";
  position: absolute;
  bottom: -16px;
  right: 10px;
  font-size: 1.5em;
  line-height: 1;
  color: var(--SmartThemeBodyColor);
}

.mes_reasoning_header {
  margin: 0;
  padding: 0;
  background: none;
}

/* * 这里的修改：
 * 1. 删除了 'font-size: 0;'
 * 2. 把 '::before' 里的样式（字体、颜色、粗细等）移到了这里
 */
.mes_reasoning_header_title {
  font-size: var(--mainFontSize);
  color: var(--SmartThemeBodyColor);
  font-weight: bold;
  font-style: italic;
}

/*
 * 这里的修改：
 * 1. 把 'content' 从 "✦ " 改成了中文 "思维链："
 */
.mes .mes_reasoning_header_title::before {
  content: "⭐："; 
  /* 如果你什么都不想要，可以把上一行 content: "思维链："; 整个删掉 */
}

.mes_reasoning_details .mes_reasoning_arrow {
  display: none;
}

/* 预设小字 */
.toggle-description {
  color: var(--SmartThemeBodyColor);
  opacity: 0.85;
}

/* 预设提示词标题 */
#completion_prompt_manager .completion_prompt_manager_header_advanced span,
#completion_prompt_manager .completion_prompt_manager_header div {
  filter: none;
  color: var(--SmartThemeBodyColor);
}

/* 预设条目 */
#completion_prompt_manager #completion_prompt_manager_list {
  gap: 5px;
}

/* 启用预设条目 */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:not(#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled) {
  border: 1px solid var(--SmartThemeBodyColor);
}

/* 未启用预设条目 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled,
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  border: none;
  color: var(--SmartThemeBodyColor);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt .prompt_manager_prompt_controls span {
  filter: none !important;
  opacity: 1 !important;
}

/* --- 世界书 (最终修复整合版) --- */

/* [关键修复] 覆盖主题的全局透明/毛玻璃效果，为世界书面板提供一个坚实的不透明背景 */
#WorldInfo {
    background-color: #1c1d1f !important; /* 使用 !important 强制覆盖主题的透明设置 */
    backdrop-filter: none !important; /* 移除毛玻璃效果 */
}

/* “自定义小说”原始的世界书样式，保留其基本结构 */
.wi-card-entry {
  border: none;
  border-radius: 0;
  margin: 10px 0;
  padding: 5px 10px;
}

.wi-card-entry:has(.killSwitch.fa-toggle-on) {
  border: 1px solid var(--SmartThemeBodyColor);
}

.select2_multi_sameline+span.select2-container .select2-selection--multiple, span.select2.select2-container .select2-selection__choice__remove, .select2_choice_clickable_buttonstyle+span.select2-container .select2-selection__choice__display, .select2_multi_sameline+span.select2-container .select2-selection__choice, .standoutHeader~.inline-drawer-content {
  border: none;
  background-color: transparent;
}

.select2-results .select2-results__option--selectable {
  opacity: 1 !important;
}


/* --- 柏柏白的世界书布局 (已深度适配并修复所有已知问题) --- */
@media screen and (max-width: 500px) {
  .world_entry {
    position: relative; /* [关键修复] 防止内部元素飞出，解决悬浮问题 */
    min-height: 140px;
    margin-top: 15px;
    background-color: #282a2d; /* [修复] 为所有条目(包括关闭的)提供不透明深色背景 */
    border: 1px solid #444;
    border-radius: 15px;

    textarea,
    input,
    select {
      border: 1px solid #444;
      background-color: #1e1f21;
      color: var(--SmartThemeBodyColor);
    }

    .world_entry_form {
      border: 1px solid #444;
    }

    .fa-circle-chevron-down.interactable.fa-fw.fa-solid,
    .fa-circle-chevron-up.interactable.fa-fw.fa-solid {
      position: absolute;
      right: 5px;
      top: 111px;
      border-radius: 5px;
      border: none;
      height: 26px;
      width: 26px;
    }

    .fa-circle-chevron-down.interactable.fa-fw.fa-solid:before,
    .fa-circle-chevron-up.interactable.fa-fw.fa-solid:before {
      width: 26px;
      height: 26px;
    }

    .world_entry_form {
      padding-bottom: 8px;
      padding-top: 5px;
      padding-left: 8px;
      padding-right: 8px;
      position: relative;
      border-radius: 15px;
    }

    .killSwitch {
      position: absolute;
      right: 10px;
      top: 67px;
      height: 14px;
      width: 15px;
      z-index: 999;
    }

    /* 世界书开关颜色 */
    .killSwitch.fa-toggle-on {
      color: rgba(255, 180, 100, 0.9) !important;
    }

    .killSwitch.fa-toggle-off {
      color: rgb(127, 127, 127) !important;
    }

    .drag-handle {
      position: absolute;
      right: 10px;
      top: 17px;
      color: var(--SmartThemeBodyColor);
    }

    .flex-container.alignitemscenter.wide100p {
      margin-right: 25px;
    }

    .move_entry_button,
    .duplicate_entry_button,
    .delete_entry_button {
      position: absolute;
      top: 111px;
      height: 25px;
      width: 25px;
      padding: 0;
      margin: 0;
      color: rgba(255, 255, 255, 0.7);
    }

    /* [布局修复] 将按钮从左侧定位改为右侧定位，解决重叠问题 */
    .delete_entry_button {
      right: 35px; /* 从右侧定位 */
    }

    .duplicate_entry_button {
      right: 65px; /* 从右侧定位 */
    }

    .move_entry_button {
      right: 95px; /* 从右侧定位 */
    }


    .text_pole {
      font-size: 13px;
      height: 25px;
      border-radius: 10px;
      background-color: transparent; 
    }

    .text_pole[name='comment'] {
      color: #888888;
      font-size: 14px;
      padding: 6px 8px;
      height: 28px;
      line-height: 14px;
    }

    .WIEntryTitleAndStatus.flex-container.flex1.alignitemscenter { min-height: 35px; }
    .WIEnteryHeaderControls.flex-container { min-height: 87px; }

    .WIEntryTitleAndStatus:has(select[name='entryStateSelector'] option[value='constant']:checked) textarea[name='comment'] { color: #0a66c2; }
    .WIEntryTitleAndStatus:has(select[name='entryStateSelector'] option[value='normal']:checked) textarea[name='comment'] { color: #2e7d32; }
    .WIEntryTitleAndStatus:has(select[name='entryStateSelector'] option[value='vectorized']:checked) textarea[name='comment'] { color: #81adb6; }

    input[name='depth'],
    input[name='order'],
    input[name='probability'] {
      width: 45px !important;
      height: 25px !important;
      border-width: 1px;
    }

    input[type='checkbox'] {
      box-shadow: none;
      background-color: rgb(127, 127, 127);
    }

    input[type='checkbox']:checked {
      background-color: rgba(255, 180, 100, 0.9);
    }

    label,
    label[data-i18n='Order:'],
    label[data-i18n='Depth:'],
    label[data-i18n='Position:'],
    label[data-i18n='Trigger %:'] {
      font-size: 11px;
      margin-top: 1px;
      margin-left: 3px;
      line-height: 13px;
      color: rgba(255, 255, 255, 0.5);
    }

    small[data-i18n='Primary Keywords'],
    small[data-i18n='Optional Filter'],
    small[data-i18n='Logic'],
    small[data-i18n='Scan Depth'],
    small[data-i18n='Case-Sensitive'],
    span[data-i18n='Content'] {
      font-size: 11px;
      margin-top: 1px;
      margin-left: 5px;
